using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 9.99m);

        Assert.AreEqual(9.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 3, price: 10.00m);

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 0, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 1, price: -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.AddItem(null!, quantity: 1, price: 10.00m));
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("NO-SUCH-SKU"));
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_LeavesOthers()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 15.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 7.50m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(string.Empty));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"));
    }
}

